select 
from question
where deleted = 0

    and subject_id = #{subjectId}


    and question_type = #{questionType}


    and difficulty = #{difficulty}


    and knowledge_point like concat('%', #{knowledgePoint}, '%')


    and title like concat('%', #{keyword}, '%')

order by id desc
limit #{offset}, #{pageSize}

select count(1)
from question
where deleted = 0

    and subject_id = #{subjectId}


    and question_type = #{questionType}


    and difficulty = #{difficulty}


    and knowledge_point like concat('%', #{knowledgePoint}, '%')


    and title like concat('%', #{keyword}, '%')

select 
from question
where deleted = 0
  and subject_id = #{subjectId}
  and question_type = #{questionType}
  and difficulty = #{difficulty}

    and knowledge_point like concat('%', #{knowledgePoint}, '%')

order by id asc
limit #{limitCount}
